where.if:
AND EXISTS (
    SELECT 1 FROM tb_company_channel_map chm 
    WHERE chm.company_id = c.company_id 
      AND chm.channel_id = #{channelId} 
      AND chm.status = 'ACTIVE'
)

mapper.select:
SELECT c.*, ch.channel_id as channel_id, ch.channel_name as channel_name, pcc.primary_contact_name as primary_contact_name, pcc.primary_contact_mobile as primary_contact_mobile FROM tb_company c LEFT JOIN tb_company_channel_map m ON c.company_id = m.company_id AND m.status = 'ACTIVE' LEFT JOIN tb_channel ch ON m.channel_id = ch.channel_id LEFT JOIN ( SELECT company_id, contact_name as primary_contact_name, mobile as primary_contact_mobile FROM ( SELECT company_id, contact_name, mobile, ROW_NUMBER() OVER(PARTITION BY company_id ORDER BY is_primary DESC, created_at DESC) as rn FROM tb_company_contact WHERE status = 'ACTIVE' ) t WHERE rn = 1 ) pcc ON pcc.company_id = c.company_id
AND c.tenant_id = #{tenantId}
AND c.company_type = #{companyType}
AND c.status = #{status}
AND (c.company_name LIKE CONCAT('%', #{searchKeyword}, '%') OR c.business_no LIKE CONCAT('%', #{searchKeyword}, '%'))
AND ch.channel_id = #{channelId}
ORDER BY c.created_at DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

mapper.update:
UPDATE tb_company
SET status = #{status}, updated_at = NOW()
WHERE company_id = #{companyId}

UPDATE tb_company_contact
SET is_primary = #{isPrimary}, updated_at = NOW()
WHERE contact_id = #{contactId}

mapper.select:
